/**
 * @summary List AI insights for workspace
 */
export const getGetAiInsightsUrl = (params?: GetAiInsightsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ai/insights?${stringifiedParams}`
    : `/api/ai/insights`;
};

export const getAiInsights = async (
  params?: GetAiInsightsParams,
  options?: RequestInit,
): Promise<AiInsight[]> => {
  return customFetch<AiInsight[]>(getGetAiInsightsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetAiInsightsQueryKey = (params?: GetAiInsightsParams) => {
  return [`/api/ai/insights`, ...(params ? [params] : [])] as const;
};

export const getGetAiInsightsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAiInsights>>,
  TError = ErrorType<unknown>,
>(
  params?: GetAiInsightsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAiInsights>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetAiInsightsQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getAiInsights>>> = ({
    signal,
  }) => getAiInsights(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAiInsights>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAiInsightsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAiInsights>>
>;
export type GetAiInsightsQueryError = ErrorType<unknown>;

/**
 * @summary List AI insights for workspace
 */

export function useGetAiInsights<
  TData = Awaited<ReturnType<typeof getAiInsights>>,
  TError = ErrorType<unknown>,
>(
  params?: GetAiInsightsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAiInsights>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAiInsightsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

